sub_queries.sql:
SELECT Year, Time FROM T22
UNION ALL
SELECT Year, Time FROM T23;

SELECT Nationality 
FROM T24 
WHERE Date_first_broken = (
  SELECT MIN(Date_first_broken) 
  FROM T24
);

SELECT Athlete, CAST(No_of_times_broken AS REAL) AS Times_Broken
FROM T24
ORDER BY Times_Broken DESC;

SELECT DISTINCT Location 
FROM (
    SELECT Location FROM T22
    UNION
    SELECT Location FROM T23
);

SELECT Time, Athlete FROM T22
UNION
SELECT Time, Athlete FROM T23;

SELECT Rank, Country, Team, Points 
FROM T83 
WHERE LOWER(Country) IN ('france', 'england', 'spain');

SELECT Year, CAST(Time AS REAL) AS Time_numeric
FROM T34
ORDER BY Year;

SELECT Athlete, Time, COUNT(*) AS Time_Count
FROM T54
GROUP BY Athlete, Time;

SELECT Location, Athlete 
FROM T34 
WHERE LOWER(Location) LIKE '%city%' OR LOWER(Location) LIKE '%polis%';

